{
  "plan_id": "mcp-management-crash-fixes",
  "revision": 2,
  "title": "MCP Management Crash Fixes — Revision 2",
  "boundary": "desktop/mcp-management-crash-fixes",
  "consumer_purpose": "Fix P0 data-loss (added MCP servers not persisting), P0 nested-dialog portal crash, and P1/P2 UX gaps in the MCP management dialog UI",
  "root_causes": [
    {
      "id": "RC-A",
      "hypothesis": "addMutation.onSuccess resets form and refetches queries but does NOT persist the new server config to electron-store via api.setMcpServers(). Servers added via the Add button vanish on restart.",
      "confidence": "high",
      "evidence": [
        "dialog-select-mcp.tsx:129-146: addMutation onSuccess only resets form state, calls queryClient.refetchQueries. No call to api.getMcpServers()/setMcpServers()",
        "dialog-select-mcp.tsx:380-397: onSave callback DOES persist via api.getMcpServers()/setMcpServers() — pattern mismatch confirms the gap"
      ]
    },
    {
      "id": "RC-B",
      "hypothesis": "DialogEditMcp renders its own <Dialog> (from @opencode-ai/ui/dialog) and calls useDialog() from @opencode-ai/ui/context/dialog. Since it is rendered inside DialogSelectMcp which also uses <Dialog>, Kobalte creates nested portals with conflicting focus traps, causing broken keyboard navigation and potential crashes.",
      "confidence": "high",
      "evidence": [
        "dialog-edit-mcp.tsx:2: imports { Dialog } from \"@opencode-ai/ui/dialog\"",
        "dialog-edit-mcp.tsx:4: imports { useDialog } from \"@opencode-ai/ui/context/dialog\"",
        "dialog-edit-mcp.tsx:16: useDialog() call inside component",
        "dialog-edit-mcp.tsx:96: renders <Dialog> wrapper",
        "dialog-select-mcp.tsx:201: parent renders nested <Dialog>"
      ]
    },
    {
      "id": "RC-C",
      "hypothesis": "handleEdit tries to find the server in electron-store. If not found (pre-persistence servers, SDK-only registration), it silently does nothing — no fallback, no error, no feedback.",
      "confidence": "high",
      "evidence": [
        "dialog-select-mcp.tsx:67-74: handleEdit finds entry in api.getMcpServers() or does nothing. No else branch, no fallback, no toast."
      ]
    },
    {
      "id": "RC-D",
      "hypothesis": "Multiple CRUD error paths use console.warn which is invisible to users. The toggle mutation has no onError handler at all.",
      "confidence": "high",
      "evidence": [
        "dialog-select-mcp.tsx:72: console.warn in handleEdit catch",
        "dialog-select-mcp.tsx:93,101: console.warn in confirmRemove catch blocks",
        "dialog-select-mcp.tsx:394: console.warn in onSave catch",
        "dialog-select-mcp.tsx:130-140: toggle mutation has no onError"
      ]
    },
    {
      "id": "RC-E",
      "hypothesis": "handleSave in dialog-edit-mcp creates a remote McpServerEntry with url() directly, without validating it is a parseable URL. Invalid URLs cause silent failures downstream.",
      "confidence": "medium",
      "evidence": [
        "dialog-edit-mcp.tsx:67-72: constructs remote entry with `url: url()` — no validation before this point"
      ]
    }
  ],
  "fixes": [
    {
      "id": "fix-B",
      "description": "Remove nested dialog portal from DialogEditMcp. Delete Dialog and useDialog imports. Replace <Dialog> wrapper with a styled <div> containing the title as a heading element and the existing form content. Remove dialog.close() calls — parent controls visibility via editingEntry signal.",
      "files": ["packages/app/src/components/dialog-edit-mcp.tsx"],
      "before": "import { Dialog } from \"@opencode-ai/ui/dialog\";\nimport { useDialog } from \"@opencode-ai/ui/context/dialog\";\n...\nexport function DialogEditMcp(props: Props) {\n  const dialog = useDialog();\n  ...\n  return (\n    <Dialog title={...} class=\"w-full max-w-[480px] mx-auto\">\n      <div class=\"flex flex-col gap-5 p-6 pt-0\">...</div>\n    </Dialog>\n  );\n}",
      "after": "// Dialog and useDialog imports removed\nexport function DialogEditMcp(props: Props) {\n  return (\n    <div class=\"w-full max-w-[480px] mx-auto flex flex-col gap-5 p-6 pt-0\">\n      <h2 class=\"text-16-medium text-text-strong mb-2\">\n        {isEditing() ? language.t(\"dialog.mcp.action.edit\") : language.t(\"dialog.mcp.addTitle\")}\n      </h2>\n      ...existing form fields...\n    </div>\n  );\n}",
      "impact": {
        "affected_files": ["packages/app/src/components/dialog-edit-mcp.tsx"],
        "tests_to_run": ["bun check packages/app"]
      },
      "risks": [
        "Styling regression if Dialog provided CSS that the outer div does not replicate",
        "Loss of dialog ARIA roles and keyboard escape handling — parent dialog handles escape already",
        "If handleSave still calls dialog.close(), it will throw because useDialog context is gone"
      ],
      "validation": [
        "Open edit dialog from MCP list → verify form renders inline without portal overlay",
        "Verify the form content and layout match the original appearance",
        "Verify Save and Cancel buttons work correctly",
        "Verify keyboard navigation (Tab, Enter, Escape) works within the dialog context"
      ]
    },
    {
      "id": "fix-A",
      "description": "Add electron-store persistence to addMutation.onSuccess. Make onSuccess async, read existing servers, append new McpServerEntry matching the constructed config, write back via api.setMcpServers(). Matches the onSave pattern at line 380 exactly.",
      "files": ["packages/app/src/components/dialog-select-mcp.tsx"],
      "before": "addMutation.onSuccess: () => {\n  setStore(\"addForm\", { name: \"\", url: \"\", error: \"\" });\n  setStore(\"mode\", \"list\");\n  queryClient.refetchQueries(queryOptions.mcp(pathKey(sync.directory)));\n}",
      "after": "addMutation.onSuccess: async (_data, input) => {\n  setStore(\"addForm\", { name: \"\", url: \"\", error: \"\" });\n  setStore(\"mode\", \"list\");\n  try {\n    const api = (window as any).api;\n    const servers = (await api?.getMcpServers?.()) ?? [];\n    servers.push({\n      name: input.name,\n      config: { type: \"remote\" as const, url: input.url, enabled: true },\n    });\n    await api?.setMcpServers?.(servers);\n  } catch (e) {\n    console.warn(\"Failed to persist new server:\", e);\n  }\n  queryClient.refetchQueries(queryOptions.mcp(pathKey(sync.directory)));\n}",
      "impact": {
        "affected_files": ["packages/app/src/components/dialog-select-mcp.tsx"],
        "tests_to_run": ["bun check packages/app"]
      },
      "risks": [
        "If api.getMcpServers() fails (e.g. store is locked), the server is added to SDK runtime but not persisted — partial failure. Error is console.warn only (Fix D upgrades this to showToast).",
        "Race condition if user rapidly clicks Add twice — second call getMcpServers might not include first server yet. Low probability due to mutation pending guard."
      ],
      "validation": [
        "Add a new MCP server via the Add form → verify it appears in the list",
        "Close and reopen the dialog → verify the server is still present",
        "Restart the app → verify the server persists in electron-store"
      ]
    },
    {
      "id": "fix-C",
      "description": "Add reconciliation fallback to handleEdit. When entry is not found in electron-store servers array, check sync.data.mcp[name] for the server name and construct a default McpServerEntry with name pre-filled. Show toast for both fallback and not-found cases.",
      "files": ["packages/app/src/components/dialog-select-mcp.tsx"],
      "before": "const entry = servers?.find((s: any) => s.name === name);\nif (entry) {\n  setEditingEntry(entry);\n}",
      "after": "const entry = servers?.find((s: any) => s.name === name);\nif (entry) {\n  setEditingEntry(entry);\n} else if (sync.data.mcp[name]) {\n  setEditingEntry({\n    name,\n    config: { type: \"remote\" as const, url: \"\", enabled: true },\n  });\n  showToast({ title: \"Server config not persisted — please re-enter details\", variant: \"warning\" });\n} else {\n  showToast({ title: \"Server not found\", description: `No server named \"${name}\"`, variant: \"error\" });\n}",
      "impact": {
        "affected_files": ["packages/app/src/components/dialog-select-mcp.tsx"],
        "tests_to_run": ["bun check packages/app"]
      },
      "risks": [
        "Fallback entry has empty URL — user must manually fill it in. They might not know what URL to enter.",
        "If sync.data.mcp[name] exists but contains a local-type server (command-based), the remote fallback is wrong type.",
        "Hardcoded English strings instead of language.t() calls — may not match i18n pattern"
      ],
      "validation": [
        "Add server → remove its electron-store entry manually → click edit → should show fallback with name pre-filled",
        "Edit a server that exists in electron-store → should work as before"
      ]
    },
    {
      "id": "fix-D",
      "description": "Replace console.warn with showToast in all CRUD error paths. Add onError handler to toggle mutation. Add import for showToast from @opencode-ai/ui/toast.",
      "files": ["packages/app/src/components/dialog-select-mcp.tsx"],
      "before": "console.warn(\"Failed to load server config for edit:\", e)\nconsole.warn(\"Disconnect failed:\", e)\nconsole.warn(\"Failed to remove from store:\", e)\nconsole.warn(\"Failed to persist edited server:\", e)\n// toggle mutation has no onError",
      "after": "showToast({ title: \"Failed to load server config\", variant: \"error\" })\nshowToast({ title: \"Disconnect failed\", variant: \"error\" })\nshowToast({ title: \"Failed to remove from store\", variant: \"error\" })\nshowToast({ title: \"Failed to save server\", variant: \"error\" })\n// toggle mutation adds: onError: () => showToast({ title: \"Toggle failed\", variant: \"error\" })",
      "impact": {
        "affected_files": ["packages/app/src/components/dialog-select-mcp.tsx"],
        "tests_to_run": ["bun check packages/app"]
      },
      "risks": [
        "showToast might not render inside a nested Dialog (mitigated by Fix B which removes nesting)",
        "Hardcoded English strings may not match the localized toast pattern used elsewhere"
      ],
      "validation": [
        "Trigger each error path → verify toast appears",
        "Toggle MCP connection when server unavailable → verify error toast appears"
      ]
    },
    {
      "id": "fix-E",
      "description": "Add URL validation in dialog-edit-mcp handleSave. Before constructing the remote McpServerEntry, validate the URL using new URL(). If invalid, show an inline error message and return without saving.",
      "files": ["packages/app/src/components/dialog-edit-mcp.tsx"],
      "before": "const handleSave = () => {\n  const timeoutVal = ...;\n  const entry: McpServerEntry = {\n    name: name(),\n    config: type() === \"local\"\n      ? { type: \"local\", ... }\n      : { type: \"remote\", url: url(), enabled: true },\n  };\n  props.onSave(entry);\n}",
      "after": "const handleSave = () => {\n  if (type() === \"remote\") {\n    try { new URL(url()); } catch { setUrlError(\"Invalid URL format\"); return; }\n  }\n  const timeoutVal = ...;\n  const entry: McpServerEntry = {\n    name: name(),\n    config: type() === \"local\"\n      ? { type: \"local\", ... }\n      : { type: \"remote\", url: url(), enabled: true },\n  };\n  props.onSave(entry);\n}",
      "impact": {
        "affected_files": ["packages/app/src/components/dialog-edit-mcp.tsx"],
        "tests_to_run": ["bun check packages/app"]
      },
      "risks": ["Minimal — purely additive validation that prevents invalid entries"],
      "validation": [
        "Enter 'not-a-url' in URL field → save should be prevented with error indicator",
        "Enter 'http://localhost:3000' → save should work normally",
        "Verify local type command entry is unaffected by the validation"
      ]
    }
  ],
  "apply_order": ["fix-B", "fix-A", "fix-C", "fix-D", "fix-E"],
  "apply_rationale": "fix-B first: Fix B removes the nested dialog portal so that Fix D (showToast) works correctly (toasts render inside the parent dialog without portal conflicts). fix-A is the P0 data-loss fix — the most critical user-facing bug. fix-C and fix-D add fallback recovery and user-visible error messages for remaining edge cases. fix-E last: purely additive validation enhancement with no dependency on other fixes.",
  "rollback_plan": "Revert each fix in reverse order (E → D → C → A → B). All fixes touch only 2 files (dialog-select-mcp.tsx and dialog-edit-mcp.tsx). Simply git checkout each file to revert all changes at once.",
  "file_summary": {
    "packages/app/src/components/dialog-select-mcp.tsx": ["fix-A", "fix-C", "fix-D"],
    "packages/app/src/components/dialog-edit-mcp.tsx": ["fix-B", "fix-E"],
    "packages/app/src/types/mcp.ts": "unchanged - no schema changes needed"
  },
  "deferred_seams": [
    "IPC channel changes for electron-store (deferred to Lane 1)",
    "Language/i18n keys for toast messages (using hardcoded English strings, deferring translation work)",
    "Unified data source for MCP server configs (separate architectural effort)"
  ]
}
